svg.script:
// Core Simulator State
let engineRunning = true;
let collectiveInput = 0.5; // Starts in mid hover
let isDragging = false;

// Physics State
let rpm = 100; // Percentage 0-110%
let descentRate = 0; // fpm (positive is down)

// Get Elements
const svgRoot = document.documentElement;
const collHitbox = document.getElementById('collHitbox');
const collKnob = document.getElementById('collKnob');
const engineBtn = document.getElementById('engineBtn');
const engineBtnBg = document.getElementById('engineBtnBg');
const engineBtnSlider = document.getElementById('engineBtnSlider');
const engineBtnText = document.getElementById('engineBtnText');
const collectiveWarning = document.getElementById('collectiveWarning');

const rpmNeedle = document.getElementById('rpmNeedle');
const rpmText = document.getElementById('rpmText');
const vsiText = document.getElementById('vsiText');
const statusText = document.getElementById('statusText');

// Airfoil Elements
const airfoilSection = document.getElementById('airfoilSection');
const vecInflow = document.getElementById('vecInflow');
const vecRot = document.getElementById('vecRot');
const vecRelWind = document.getElementById('vecRelWind');
const vecLift = document.getElementById('vecLift');
const vecDrag = document.getElementById('vecDrag');
const vecTAF = document.getElementById('vecTAF');
const lblInflow = document.getElementById('lblInflow');
const lblRot = document.getElementById('lblRot');
const lblRelWind = document.getElementById('lblRelWind');
const tafExplanation = document.getElementById('tafExplanation');
const tafLine1 = document.getElementById('tafLine1');
const tafLine2 = document.getElementById('tafLine2');

// Blade Region Elements
const regStalled = document.getElementById('regStalled');
const regDriving = document.getElementById('regDriving');
const regDriven = document.getElementById('regDriven');

// Flight Profile Elements
const speedLines = document.getElementById('speedLines').querySelectorAll('line');
let speedLineOffsets = [0, 0, 0, 0, 0];
const airflowArrows = [
    document.getElementById('af1'),
    document.getElementById('af2'),
    document.getElementById('af3')
];
const heliRotor = document.getElementById('heliRotor');

// Engine Toggle Logic
engineBtn.addEventListener('click', () => {
  engineRunning = !engineRunning;

  if (engineRunning) {
    engineBtnBg.setAttribute('fill', '#10b981'); // Green
    engineBtnSlider.setAttribute('x', '95');
    engineBtnText.setAttribute('x', '45');
    engineBtnText.textContent = 'NORMAL';
  } else {
    engineBtnBg.setAttribute('fill', '#ef4444'); // Red
    engineBtnSlider.setAttribute('x', '5');
    engineBtnText.setAttribute('x', '85');
    engineBtnText.textContent = 'FAILED';
  }
});

// Collective Input Handling
function getMouseY(e) {
  let clientY = e.clientY;
  if (e.touches && e.touches.length > 0) {
    clientY = e.touches[0].clientY;
  }
  const pt = svgRoot.createSVGPoint();
  pt.x = 0; pt.y = clientY;
  const ctm = collHitbox.getScreenCTM().inverse();
  return pt.matrixTransform(ctm).y;
}

function startDrag(e) {
  e.preventDefault();
  isDragging = true;
  updateLever(e);
}

function drag(e) {
  if (!isDragging) return;
  e.preventDefault();
  updateLever(e);
}

function stopDrag() {
  isDragging = false;
}

function updateLever(e) {
  let y = getMouseY(e);
  // Track is from y=30 to y=190 (height 160)
  // Map y=190 -> collective=0, y=30 -> collective=1
  let val = 1 - ((y - 30) / 160);
  collectiveInput = Math.max(0, Math.min(1, val));
}

collHitbox.addEventListener('mousedown', startDrag);
collHitbox.addEventListener('touchstart', startDrag, {passive: false});
window.addEventListener('mousemove', drag);
window.addEventListener('touchmove', drag, {passive: false});
window.addEventListener('mouseup', stopDrag);
window.addEventListener('touchend', stopDrag);

// Physics Update Loop
let lastTime = 0;

function animate(time) {
  const dt = (time - lastTime) / 1000 || 0.016;
  lastTime = time;

  // 1. UPDATE PHYSICS
  if (engineRunning) {
    // Engine governs RPM
    rpm += (100 - rpm) * 0.1;

    // Descent rate based purely on collective (simplified for hover state)
    // collective 0.5 = 0 fpm. 0 = 1000 fpm down. 1 = 1000 fpm up.
    let targetDescent = (0.5 - collectiveInput) * 2000;
    descentRate += (targetDescent - descentRate) * 0.1;

  } else {
    // AUTOROTATION PHYSICS
    // Descent rate rapidly increases if no engine, governed by rotor drag and lift
    let targetDescent = 1500 + (collectiveInput * 1500); // Higher collective = drops faster initially as rpm bleeds
    descentRate += (targetDescent - descentRate) * 0.05;

    // RPM is driven by upward flow (descent rate) VS aerodynamic drag (collective)
    // Optimal autorotation collective is near 0.

    // Upward driving force proportional to descent rate
    let drivingForce = (descentRate / 1500) * 1.5; 

    // Drag penalty heavily weighted by collective
    let dragPenalty = 0.5 + (collectiveInput * 3.0); 

    // RPM acceleration
    let rpmAccel = (drivingForce - dragPenalty) * 20; 

    rpm += rpmAccel * dt;

    // Crash condition constraint
    if (rpm < 0) rpm = 0;
  }

  // 2. UPDATE UI

  // Controls UI
  const knobY = 190 - (collectiveInput * 160);
  collKnob.setAttribute('transform', `translate(0, ${knobY})`);

  if (!engineRunning && collectiveInput > 0.2 && rpm > 20) {
    collectiveWarning.setAttribute('visibility', 'visible');
  } else {
    collectiveWarning.setAttribute('visibility', 'hidden');
  }

  // Gauges UI
  // RPM needle maps: 0% -> -140 deg, 100% -> 20 deg, 110% -> 50 deg
  // Slope: 160 deg range / 100 units = 1.6
  let rpmAngle = -140 + (rpm * 1.6);
  if (rpmAngle > 80) rpmAngle = 80;
  rpmNeedle.setAttribute('transform', `rotate(${rpmAngle})`);
  rpmText.textContent = Math.round(rpm) + '%';

  // Color RPM text
  if (rpm < 75 || rpm > 104) rpmText.setAttribute('fill', '#ef4444');
  else if (rpm < 90) rpmText.setAttribute('fill', '#f59e0b');
  else rpmText.setAttribute('fill', '#10b981');

  vsiText.textContent = Math.round(descentRate) + ' fpm ' + (descentRate > 0 ? '⬇' : descentRate < 0 ? '⬆' : '');

  // Status Text UI
  if (engineRunning) {
    statusText.textContent = "POWERED FLIGHT";
    statusText.setAttribute('fill', '#10b981');
  } else {
    if (rpm < 75) {
      statusText.textContent = "ROTOR STALL / FATAL";
      statusText.setAttribute('fill', '#ef4444');
    } else {
      statusText.textContent = "GLIDING (AUTOROTATION)";
      statusText.setAttribute('fill', '#f59e0b');
    }
  }

  // 3. UPDATE AIRFOIL & VECTORS
  // Base blade pitch is tied to collective
  let pitchDeg = 2 + (collectiveInput * 10);
  airfoilSection.setAttribute('transform', `rotate(${-pitchDeg})`);

  // Draw vectors relative to origin (0,0) at quarter-chord
  let inflowMag = 0;
  let rotMag = rpm * 1.2; // Visual scale

  if (engineRunning) {
    // Powered hover: Airflow is pulled DOWN by the rotor
    inflowMag = -40; // Downward
    lblInflow.textContent = "Induced Flow (Down)";
    lblInflow.setAttribute('y', '-50');
    vecInflow.setAttribute('y1', '-80');
  } else {
    // Autorotation: Airflow pushed UP by descent
    inflowMag = (descentRate / 1500) * 80; 
    lblInflow.textContent = "Upward Flow";
    lblInflow.setAttribute('y', '45');
    vecInflow.setAttribute('y1', '80');
  }

  // Rotational Vector (always horizontal, leftward relative to blade)
  vecRot.setAttribute('x1', -rotMag);
  vecRot.setAttribute('y1', inflowMag);
  vecRot.setAttribute('y2', inflowMag);
  lblRot.setAttribute('x', -rotMag/2);
  lblRot.setAttribute('y', inflowMag + 15);

  // Relative Wind (Resultant)
  vecRelWind.setAttribute('x1', -rotMag);
  vecRelWind.setAttribute('y1', inflowMag);

  // Calculate Angle of Attack
  let relWindAngleRad = Math.atan2(inflowMag, -rotMag);
  let pitchRad = pitchDeg * (Math.PI / 180);
  let aoaRad = relWindAngleRad + pitchRad;

  // Position Label (pushed perpendicularly away from the vector to prevent overlapping)
  lblRelWind.setAttribute('x', -rotMag/2 - 10);
  lblRelWind.setAttribute('y', inflowMag/2 + 25);
  lblRelWind.setAttribute('transform', `rotate(${relWindAngleRad * 180/Math.PI}, ${-rotMag/2 - 10}, ${inflowMag/2 + 25})`);

  // Calculate Lift and Drag magnitudes based on AoA and velocity
  let velocitySq = Math.pow(rotMag, 2) + Math.pow(inflowMag, 2);

  // Simplified lift/drag curves
  let liftCoef = Math.sin(aoaRad * 2); // Peaks around 45deg artificially, good enough visually
  let dragCoef = 0.1 + Math.pow(Math.sin(aoaRad), 2);

  // Stall condition override
  if (aoaRad > 0.3 || rpm < 40) { // ~17 degrees
    liftCoef = 0.1;
    dragCoef += 1.0;
  }

  let liftMag = liftCoef * (velocitySq / 150);
  let dragMag = dragCoef * (velocitySq / 150);

  // Calculate vector endpoints
  // Lift is perpendicular to relative wind (rotate 90 deg clockwise in SVG coords)
  let liftX = liftMag * Math.sin(relWindAngleRad);
  let liftY = liftMag * -Math.cos(relWindAngleRad);

  vecLift.setAttribute('x2', liftX);
  vecLift.setAttribute('y2', liftY);

  // Drag is parallel to relative wind
  let dragX = dragMag * Math.cos(relWindAngleRad);
  let dragY = dragMag * Math.sin(relWindAngleRad);

  vecDrag.setAttribute('x2', dragX);
  vecDrag.setAttribute('y2', dragY);

  // Total Aerodynamic Force (TAF) is vector sum
  let tafX = liftX + dragX;
  let tafY = liftY + dragY;

  vecTAF.setAttribute('x2', tafX);
  vecTAF.setAttribute('y2', tafY);

  // Analyze TAF to update multi-line explanation
  if (engineRunning) {
    tafLine1.textContent = "POWERED: TAF points backwards, creating";
    tafLine2.textContent = "aerodynamic drag the engine must overcome.";
    tafExplanation.setAttribute('fill', '#0ea5e9');
  } else {
    if (tafX < -5 && rpm > 40) { // TAF points forward
      tafLine1.textContent = "AUTOROTATING: TAF points FORWARD of the";
      tafLine2.textContent = "axis of rotation, accelerating the blade!";
      tafExplanation.setAttribute('fill', '#10b981');
    } else {
      tafLine1.textContent = "STALLED: TAF points BACKWARD.";
      tafLine2.textContent = "Blade is slowing down rapidly.";
      tafExplanation.setAttribute('fill', '#ef4444');
    }
  }

  // 4. UPDATE BLADE REGIONS
  if (engineRunning) {
    regStalled.setAttribute('width', 20);
    regDriving.setAttribute('x', 35);
    regDriving.setAttribute('width', 0); // No driving region in powered flight
    regDriven.setAttribute('x', 35);
    regDriven.setAttribute('width', 160);
  } else {
    // Autorotation regions depend on RPM and collective
    // High collective = big stalled region
    let stallWidth = 20 + (collectiveInput * 80);
    if (rpm < 50) stallWidth = 180; // All stalled

    regStalled.setAttribute('width', stallWidth);

    let drivingStart = 15 + stallWidth;
    let drivingWidth = (rpm > 50) ? Math.max(0, 100 - (collectiveInput * 50)) : 0;

    regDriving.setAttribute('x', drivingStart);
    regDriving.setAttribute('width', drivingWidth);

    let drivenStart = drivingStart + drivingWidth;
    let drivenWidth = 195 - drivenStart;

    regDriven.setAttribute('x', drivenStart);
    regDriven.setAttribute('width', Math.max(0, drivenWidth));
  }

  // 5. UPDATE FLIGHT PROFILE (Right Column)
  // Speed lines movement
  let visualDescentSpeed = descentRate * 0.01;
  speedLines.forEach((line, i) => {
    speedLineOffsets[i] = (speedLineOffsets[i] - visualDescentSpeed) % 540;
    if (speedLineOffsets[i] < -100) speedLineOffsets[i] += 640;
    if (speedLineOffsets[i] > 540) speedLineOffsets[i] -= 640;
    line.setAttribute('transform', `translate(0, ${speedLineOffsets[i]})`);
  });

  // Rotor visual blur depends on RPM
  let opacity = Math.max(0.2, (rpm / 100) * 0.8);
  heliRotor.setAttribute('opacity', opacity);

  // Airflow arrows direction
  airflowArrows.forEach(arrow => {
    if (engineRunning && descentRate <= 0) {
      // Pointing Down
      arrow.setAttribute('y1', arrow.getAttribute('x1') === '135' ? '180' : '200');
      arrow.setAttribute('y2', arrow.getAttribute('x1') === '135' ? '320' : '300');
      arrow.setAttribute('marker-end', 'url(#arrowFlowDown)');
      arrow.setAttribute('marker-start', '');
    } else {
      // Pointing Up
      arrow.setAttribute('y2', arrow.getAttribute('x1') === '135' ? '180' : '200');
      arrow.setAttribute('y1', arrow.getAttribute('x1') === '135' ? '320' : '300');
      arrow.setAttribute('marker-end', 'url(#arrowFlowUp)');
      arrow.setAttribute('marker-start', '');
    }
  });


  requestAnimationFrame(animate);
}

// Initialize line offsets randomly
speedLines.forEach((_, i) => speedLineOffsets[i] = Math.random() * 500);

// Start Loop
requestAnimationFrame(animate);
